// Package planstore provides a Store interface for plan state persistence,
// with a SQLite implementation for direct DB access and an HTTP implementation
// for client-server communication.
package taskstore

import "time"

// Status represents the lifecycle state of a plan.
// These constants mirror taskstate.Status to keep planstore self-contained
// and avoid circular imports.
type Status string

const (
	StatusReady        Status = "ready"
	StatusDone         Status = "done"
	StatusReviewing    Status = "reviewing"
	StatusCancelled    Status = "cancelled"
	StatusPlanning     Status = "planning"
	StatusImplementing Status = "implementing"
)

package taskstore_test

import (
	"testing"
	"time"

	"github.com/kastheco/kasmos/config/taskstore"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func newTestStore(t *testing.T) taskstore.Store {
	t.Helper()
	store, err := taskstore.NewSQLiteStore(":memory:")
	require.NoError(t, err)
	t.Cleanup(func() { store.Close() })
	return store
}

func TestSQLiteStore_CreateAndGet(t *testing.T) {

package taskstore

import "testing"

// NewTestSQLiteStore creates an in-memory SQLiteStore for use in tests.
// It registers a cleanup function to close the store when the test completes.
// This is exported so external packages can use it in their tests.
func NewTestSQLiteStore(t testing.TB) Store {
	t.Helper()
	store, err := NewSQLiteStore(":memory:")
	if err != nil {
		t.Fatalf("NewTestSQLiteStore: %v", err)
	}
	t.Cleanup(func() { store.Close() })
	return store
}

